413→    cursor: pointer;
414→    background: none;
415→    border: 1px solid var(--border-card);
416→    border-radius: 20px;
417→    padding: 0.3rem 0.85rem;
418→    margin-top: 0.4rem;
419→    font-family: var(--font-ui);
420→    font-size: 0.72rem;
