530→        font-size: 0.65rem;
531→    }
532→    .cm-reply-btn,
533→    .cm-toggle-replies-btn {
534→        font-size: 0.68rem;
535→    }
536→    .cm-textarea {
537→        font-size: 0.8rem;
538→    }
539→    .cm-submit-btn {
540→        font-size: 0.72rem;
541→        padding: 0.3rem 0.9rem;
542→    }
543→    .cm-replies-thread {
544→        padding-left: 0.75rem;
545→    }
