  1→import { useEffect, useRef, useState } from "react"
  2→import { useAuth } from "../../Context/useAuth";
  3→import { MoonLoader } from "react-spinners";
  4→import { addReply, getPostReplies } from "../../../API/Api";
  5→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  6→import { handleClickProfile } from "../../../helpers/handleClicks";
  7→import { useNavigate } from "react-router-dom";
  8→import { motion, AnimatePresence } from "framer-motion";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→import ReplyContextChip from "./ReplyContextChip";
 12→import useTextareaMention from "../mentions/useTextareaMention";
 13→import MentionDropdown from "../mentions/MentionDropdown";
 14→import MentionText from "../mentions/MentionText";
 15→import { getBadgeRingClass } from "../../utils/badgeRingClass";
 16→
 17→const incrementReplyCount = (old, parentId) => {
 18→    if (!old || !Array.isArray(old.pages)) return old;
 19→
 20→    return {
 21→        ...old,
 22→        pages: old.pages.map((page) => ({
 23→            ...page,
 24→            comments: Array.isArray(page?.comments)
 25→                ? page.comments.map((comment) => {
 26→                    if (comment?.id !== parentId) return comment;
 27→                    return {
 28→                        ...comment,
 29→                        reply_count: (comment?.reply_count || 0) + 1,
 30→                    };
 31→                })
 32→                : page?.comments,
 33→        })),
 34→    };
 35→};
 36→
 37→
 38→const CommentsCards = ({comments, postId}) =>{
 39→    const {user, session} = useAuth();
 40→    const userId = user?.userData[0].id;
 41→    const queryClient = useQueryClient();
 42→
 43→    const [showReplyInput, setShowReplyInput] = useState(false);
 44→    const [showReplies, setShowReplies] = useState(false);
 45→
 46→    const [reply, setReply] = useState('')
 47→    const [replyLoaderId, setReplyLoaderId] = useState('');
 48→
 49→    const navigate = useNavigate();
 50→    const replyInputRef = useRef(null);
 51→
 52→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(reply, setReply, replyInputRef, 200, userId);
 53→
 54→    const clickProfile = handleClickProfile(navigate);
 55→
 56→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchingNextPage} = useInfiniteQuery({
 57→        queryKey: ['getPostReplies', comments.id],
 58→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 59→        getNextPageParam: (lastPage) => {
 60→            if(lastPage.hasMore){
 61→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 62→                return lastReply.id;
 63→            } else{
 64→                return undefined
 65→            }
 66→        },
 67→        refetchOnWindowFocus: false,
 68→        enabled: showReplies,
 69→        staleTime: 1000 * 60 * 5
 70→    })
 71→
 72→    const handleClickReplyButton = (e) =>{
 73→        e.stopPropagation();
 74→        setShowReplyInput(!showReplyInput);
 75→    }
 76→
 77→    const handleShowMoreReplies = () => {
 78→        if(!isFetchingNextPage){
 79→            fetchNextPage();
 80→        }
 81→    }
 82→
 83→    const submitReply = async(parent_id, receiver_id) => {
 84→        const trimmedReply = reply.trim();
 85→        if (!trimmedReply) return;
 86→
 87→        setReplyLoaderId(parent_id)
 88→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 89→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 90→
 91→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 92→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 93→
 94→        const optimisticReply = {
 95→            id: `optimistic-reply-${Date.now()}`,
 96→            post_id: postId,
 97→            parent_id: parent_id,
 98→            comment: trimmedReply,
 99→            created_at: new Date().toISOString(),
100→            user_id: user?.userData?.[0]?.id,
101→            users: {
102→                id: user?.userData?.[0]?.id,
103→                name: user?.userData?.[0]?.name,
104→                image_url: user?.userData?.[0]?.image_url,
105→                badge: user?.userData?.[0]?.badge,
106→            },
107→            reply_count: 0,
108→        };
109→
110→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
111→            if (!old || !Array.isArray(old.pages)) {
112→                return {
113→                    pageParams: [null],
114→                    pages: [{ data: [optimisticReply], hasMore: false }],
115→                };
116→            }
117→
118→            return {
119→                ...old,
120→                pages: old.pages.map((page, index) =>
121→                    index === 0
122→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
123→                        : page
124→                ),
125→            };
126→        });
127→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
128→
129→        try {
130→            const formdata = new FormData();
131→            formdata.append('reply', trimmedReply);
132→
133→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
134→            if(message){
135→                // console.log(message);
136→            }
137→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
138→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
139→            setReply('')
140→            setShowReplies(true)
141→        } catch (error) {
142→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
143→            queryClient.setQueryData(['postComments', postId], previousComments);
144→            setReply('')
145→            throw new Error('error adding replies')
146→        } finally {
147→            setReplyLoaderId('')
148→            setShowReplyInput(false);
149→        }
150→    }
151→
152→    useEffect(() =>{
153→        if(showReplyInput && replyInputRef.current){
154→            const timer = setTimeout(() => {
155→                replyInputRef.current.focus();
156→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
157→            }, 50);
158→
159→            return () => {
160→                clearTimeout(timer)
161→            }
162→        }
163→    }, [showReplyInput])
164→
165→    const replies = data?.pages.flatMap((page) => page.data) || [];
166→
167→    return(
168→        <div className={`cm-card ${comments?.parent_id ? 'cm-card--reply' : ''}`}>
169→            {comments?.parent_id && <div className="cm-thread-line" />}
170→
171→            <div className="cm-card-content">
172→                <div className="cm-user-row">
173→                    <div
174→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
175→                        className={`cm-avatar-container ${getBadgeRingClass(comments?.users?.badge, 'cm-ring')}`}
176→                    >
177→                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
178→                    </div>
179→                    <span
180→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
181→                        className="cm-username"
182→                    >
183→                        {comments?.users?.name}
184→                    </span>
185→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
186→                    <span className="cm-dot">&middot;</span>
187→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
188→                </div>
189→
190→                <p className="cm-body"><MentionText text={comments?.comment} /></p>
191→
192→                <div className="cm-card-actions">
193→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
194→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
195→                            <polyline points="9 17 4 12 9 7" />
196→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
197→                        </svg>
198→                        Reply
199→                    </button>
200→
201→                    {comments?.reply_count > 0 && (
202→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
203→                            <motion.svg
204→                                width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
205→                                animate={{ rotate: showReplies ? 180 : 0 }}
206→                                transition={{ duration: 0.2 }}
207→                            >
208→                                <polyline points="6 9 12 15 18 9" />
209→                            </motion.svg>
210→                            <span className="cm-replies-count-badge">{comments?.reply_count}</span>
211→                            {showReplies ? 'Hide replies' : 'View replies'}
212→                        </button>
213→                    )}
214→                </div>
215→
216→                {replyLoaderId === comments.id && (
217→                    <div className="cm-reply-loading">
218→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
219→                    </div>
220→                )}
221→
222→                <AnimatePresence>
223→                    {showReplyInput && (
224→                        <motion.div
225→                            initial={{ height: 0, opacity: 0 }}
226→                            animate={{ height: "auto", opacity: 1 }}
227→                            exit={{ height: 0, opacity: 0 }}
228→                            transition={{ duration: 0.2 }}
229→                            className="cm-reply-input-wrapper"
230→                        >
231→                            <ReplyContextChip name={comments?.users?.name} onDismiss={(e) => handleClickReplyButton(e)} />
232→                            <textarea
233→                                ref={replyInputRef}
234→                                maxLength={200}
235→                                value={reply}
236→                                onChange={(e) => { setReply(e.target.value); mentionTextareaProps.onChange(e); }}
237→                                onKeyDown={mentionTextareaProps.onKeyDown}
238→                                onKeyUp={mentionTextareaProps.onKeyUp}
239→                                className="cm-reply-textarea"
240→                                placeholder={`Replying to ${comments?.users?.name}...`}
241→                                rows={1}
242→                            />
243→                            <MentionDropdown {...mentionDropdownProps} />
244→                            <div className="cm-reply-action-row">
245→                                <span className={`cm-reply-char-count ${reply.length > 199 ? 'cm-char-limit' : ''}`}>
246→                                    {reply.length}/200
247→                                </span>
248→                                <button
249→                                    onClick={() => submitReply(comments?.id, comments?.users?.id)}
250→                                    className="cm-reply-submit-btn"
251→                                    disabled={!reply.trim()}
252→                                >
253→                                    Submit
254→                                </button>
255→                            </div>
256→                        </motion.div>
257→                    )}
258→                </AnimatePresence>
259→
260→                <AnimatePresence>
261→                    {showReplies && (
262→                        <motion.div
263→                            initial={{ opacity: 0 }}
264→                            animate={{ opacity: 1 }}
265→                            exit={{ opacity: 0 }}
266→                            transition={{ duration: 0.2 }}
267→                            className="cm-replies-thread"
268→                        >
269→                            {replies?.map((r) => (
270→                                <CommentsCards postId={postId} key={r.id} comments={r}/>
271→                            ))}
272→
273→                            {hasNextPage && (
274→                                <button onClick={handleShowMoreReplies} className="cm-show-more-replies">
275→                                    {isFetchingNextPage ? 'Loading...' : 'Show more replies'}
276→                                </button>
277→                            )}
278→                        </motion.div>
279→                    )}
280→                </AnimatePresence>
281→            </div>
282→        </div>
283→    )
284→}
285→
286→export default CommentsCards;
